const response = $input.first();
const text = response.json.content[0].text;
const fs = require('fs');

// Limpar markdown code fences se presentes
const clean = text
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

let topics;
try {
  topics = JSON.parse(clean);
} catch (e) {
  const jsonMatch = clean.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    topics = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('Não foi possível parsear JSON dos tópicos: ' + e.message);
  }
}

if (!Array.isArray(topics)) {
  throw new Error('Resposta não é um array de tópicos');
}

// Deduplicação — filtrar tópicos já usados em runs anteriores
const outputDir = process.env.OUTPUT_DIR || '/data/output';
const usedFile = `${outputDir}/used_topics.json`;

let usedTopics = [];
try {
  usedTopics = JSON.parse(fs.readFileSync(usedFile, 'utf8'));
} catch (e) {
  // Arquivo ainda não existe — começa do zero
}

const usedKeys = new Set(usedTopics.map(t => t.toLowerCase().trim()));
let filtered = topics.filter(t => !usedKeys.has((t.milagre_de_jesus || '').toLowerCase().trim()));

if (filtered.length === 0) {
  console.warn('Todos os tópicos já foram usados anteriormente — reutilizando lista original');
  filtered = topics;
}

// Salvar novos tópicos usados (mantém histórico dos últimos 100)
const toRegister = filtered.map(t => t.milagre_de_jesus);
const updated = [...usedTopics, ...toRegister].slice(-100);
try {
  fs.mkdirSync(outputDir, { recursive: true });
  fs.writeFileSync(usedFile, JSON.stringify(updated, null, 2));
} catch (e) {
  console.error('Erro ao salvar used_topics.json:', e.message);
}

const runId = $('Set Config').first().json.runId;

return filtered.map((topic, index) => ({
  json: {
    ...topic,
    runId,
    topicIndex: index + 1,
    videoId: `${runId}_video_${String(index + 1).padStart(2, '0')}`
  }
}));

const cmdOutput = $input.first().json.stdout || '';
const outputMatch = cmdOutput.match(/OUTPUT:(.+)/);
const finalPath = outputMatch ? outputMatch[1].trim() : null;

if (!finalPath) {
  throw new Error('FFmpeg não retornou caminho do arquivo final');
}

const prevData = $('Sub: Generate Content').first().json;

return [{
  json: {
    videoId: prevData.videoId,
    finalVideoPath: finalPath,
    titulo: prevData.titulo,
    descricao: prevData.descricao,
    hashtags: prevData.hashtags,
    duracao: prevData.duracao_total_segundos,
    createdAt: new Date().toISOString(),
    published: false,
    platforms: []
  }
}];

// Salva metadados do vídeo em JSON
const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const metaDir = `${process.env.OUTPUT_DIR}/scripts`;
const metaFile = `${metaDir}/${data.videoId}_metadata.json`;

try {
  fs.mkdirSync(metaDir, { recursive: true });
  fs.writeFileSync(metaFile, JSON.stringify(data, null, 2));
  console.log(`Metadata salvo em: ${metaFile}`);
} catch (e) {
  console.error('Erro ao salvar metadata:', e.message);
}

return [{ json: { ...data, metadataFile: metaFile, status: 'completed' } }];

// Quando todos os vídeos do lote foram processados
const allResults = $input.all();
const summary = {
  runId: allResults[0]?.json?.videoId?.split('_video_')[0],
  totalVideos: allResults.length,
  completedAt: new Date().toISOString(),
  videos: allResults.map(r => ({
    videoId: r.json.videoId,
    titulo: r.json.titulo,
    path: r.json.finalVideoPath,
    status: r.json.status
  }))
};

console.log('BATCH SUMMARY:', JSON.stringify(summary, null, 2));
return [{ json: summary }];
